#!/usr/bin/env python3
"""
chartnav_security_integrate.py
ChartNav Security Integration Executor

Usage:
    python3 chartnav_security_integrate.py [REPO_ROOT]

Default REPO_ROOT: current directory
"""

import sys
import os
import re
import json
import shutil
import base64
import subprocess
import textwrap
from pathlib import Path
from datetime import datetime

# ── Colour helpers ─────────────────────────────────────────────────────────────

RESET  = "\033[0m"
GREEN  = "\033[32m"
YELLOW = "\033[33m"
RED    = "\033[31m"
CYAN   = "\033[36m"
BOLD   = "\033[1m"

def ok(msg):   print(f"{GREEN}  ✓ {msg}{RESET}")
def warn(msg): print(f"{YELLOW}  ⚠ {msg}{RESET}")
def err(msg):  print(f"{RED}  ✗ {msg}{RESET}")
def info(msg): print(f"{CYAN}  → {msg}{RESET}")
def head(msg): print(f"\n{BOLD}{msg}{RESET}")


# ── Embedded assets (base64) ─────────────────────────────────────────────────

ASSETS_B64 = {
    "AI_GOVERNANCE_PY": "",
    "AI_SECURITY_PY": "",
    "ADMIN_SECURITY_PY": "",
    "TEST_AI_SECURITY_PY": "",
    "SECURITY_TSX": "",
    "SECURITY_JSON": "",
    "STRIP_TSX": "",
    "SECURITY_CSS": "",
    "CHARTNAVMD_HTML": "",
    "CHARTNAVMD_DNS_MD": "",
}

# ── Asset accessor ─────────────────────────────────────────────────────────────

def asset(key: str) -> str:
    """Decode and return an embedded asset as a string."""
    raw = ASSETS_B64.get(key, "")
    if not raw or raw.startswith("PLACEHOLDER"):
        raise RuntimeError(f"Asset '{key}' not embedded. Run the bundler first.")
    return base64.b64decode(raw).decode("utf-8")

# ── Repo detection ─────────────────────────────────────────────────────────────

def detect_repo(root: Path) -> dict:
    """Walk the repo and return a map of known paths."""
    info(f"Detecting repo layout from: {root}")
    r = {}

    # Frontend
    for candidate in [
        root / "src" / "App.tsx",
        root / "App.tsx",
    ]:
        if candidate.exists():
            r["app_tsx"] = candidate
            r["src_root"] = candidate.parent
            break

    if "src_root" not in r:
        raise RuntimeError("Cannot find App.tsx -- is REPO_ROOT the monorepo root?")

    src = r["src_root"]

    r["pages_chartnav"]      = src / "pages" / "chartnav"
    r["content_chartnav"]    = src / "content" / "chartnav"
    r["components_chartnav"] = src / "components" / "chartnav"
    r["home_json"]           = src / "content"    / "chartnav" / "home.en.json"
    r["chartnav_css"]        = src / "components" / "chartnav" / "chartnav.css"
    r["home_tsx"]            = src / "pages"      / "chartnav" / "Home.tsx"
    r["sitemap"]             = root / "public" / "sitemap.xml"
    r["robots"]              = root / "public" / "robots.txt"

    # StickyNav -- find by glob
    comp_dir = src / "components" / "chartnav"
    if comp_dir.exists():
        for candidate in comp_dir.glob("*.tsx"):
            if "sticky" in candidate.name.lower() or "nav" in candidate.name.lower():
                r["sticky_nav"] = candidate
                break

    # Backend -- look for FastAPI app
    for api_root_candidate in [
        root / "apps" / "api",
        root / "api",
        root / "backend",
    ]:
        if api_root_candidate.exists():
            r["api_root"] = api_root_candidate
            break

    if "api_root" in r:
        api = r["api_root"]
        for main_candidate in [
            api / "app"  / "main.py",
            api / "main.py",
            api / "app"  / "app.py",
        ]:
            if main_candidate.exists():
                r["api_main"] = main_candidate
                r["api_app"]  = main_candidate.parent
                break

        # Services and routes dirs
        for sub in ["app", "."]:
            s_dir = api / sub / "services"
            r_dir = api / sub / "routes"
            t_dir = api / "tests"
            if s_dir.exists(): r["api_services"] = s_dir
            if r_dir.exists(): r["api_routes"]   = r_dir
            if t_dir.exists(): r["api_tests"]     = t_dir

    # package.json -- frontend build
    for pj in [root / "package.json", root / "apps" / "web" / "package.json"]:
        if pj.exists():
            r["package_json"] = pj
            r["npm_cwd"]      = pj.parent
            break

    return r

# ── Backup helper ──────────────────────────────────────────────────────────────

BACKUP_DIR: Path | None = None

def backup(path: Path):
    global BACKUP_DIR
    if not path.exists():
        return
    BACKUP_DIR.mkdir(parents=True, exist_ok=True)
    dest = BACKUP_DIR / path.name
    shutil.copy2(path, dest)
    info(f"Backed up: {path.name}")

# ── Auth/DB introspection ──────────────────────────────────────────────────────

def detect_auth_import(api_routes_dir: Path | None) -> tuple[str, str]:
    """
    Returns (module_path, function_name) for the role-based auth dependency.
    Falls back to the generated default.
    """
    if not api_routes_dir or not api_routes_dir.exists():
        return ("app.core.auth", "require_roles")

    patterns = [
        r"from\s+([\w.]+)\s+import\s+.*?(require_roles?|role_required|check_role|has_role)",
        r"Depends\((require_roles?|role_required|check_role)\(",
    ]

    for py in api_routes_dir.rglob("*.py"):
        try:
            text = py.read_text(errors="replace")
        except Exception:
            continue
        for pat in patterns:
            m = re.search(pat, text)
            if m:
                groups = m.groups()
                mod  = groups[0] if len(groups) > 1 else "app.core.auth"
                func = groups[-1]
                info(f"Detected auth: from {mod} import {func}  (in {py.name})")
                return (mod, func)

    warn("Could not detect auth function -- defaulting to require_roles")
    return ("app.core.auth", "require_roles")


def detect_session_import(api_routes_dir: Path | None) -> tuple[str, str]:
    """
    Returns (module_path, function_name) for the DB session dependency.
    """
    if not api_routes_dir or not api_routes_dir.exists():
        return ("app.core.database", "get_async_session")

    patterns = [
        r"from\s+([\w.]+)\s+import\s+.*?(get_async_session|get_db|get_session|async_session)",
        r"Depends\((get_async_session|get_db|get_session)\)",
    ]

    for py in api_routes_dir.rglob("*.py"):
        try:
            text = py.read_text(errors="replace")
        except Exception:
            continue
        for pat in patterns:
            m = re.search(pat, text)
            if m:
                groups = m.groups()
                mod  = groups[0] if len(groups) > 1 else "app.core.database"
                func = groups[-1]
                info(f"Detected session: from {mod} import {func}  (in {py.name})")
                return (mod, func)

    warn("Could not detect DB session -- defaulting to get_async_session")
    return ("app.core.database", "get_async_session")

# ── File writers ───────────────────────────────────────────────────────────────

def write_file(path: Path, content: str, label: str):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
    ok(f"Written: {label}  ({len(content):,} chars)")


def ensure_dir(path: Path):
    path.mkdir(parents=True, exist_ok=True)

# ── Step implementations ───────────────────────────────────────────────────────

def step_backend(r: dict):
    head("STEP 1 -- Backend files")

    services = r.get("api_services")
    routes   = r.get("api_routes")
    tests    = r.get("api_tests")

    if not services:
        warn("No services directory found -- skipping backend copy")
        return

    backup(services / "ai_governance.py")
    backup(services / "ai_security.py")
    write_file(services / "ai_governance.py", asset("AI_GOVERNANCE_PY"), "ai_governance.py")
    write_file(services / "ai_security.py",   asset("AI_SECURITY_PY"),   "ai_security.py")

    if routes:
        backup(routes / "admin_security.py")
        write_file(routes / "admin_security.py", asset("ADMIN_SECURITY_PY"), "admin_security.py")

    if tests:
        write_file(tests / "test_ai_security.py", asset("TEST_AI_SECURITY_PY"), "test_ai_security.py")
    elif services:
        tests_guess = services.parent.parent / "tests"
        tests_guess.mkdir(parents=True, exist_ok=True)
        write_file(tests_guess / "test_ai_security.py", asset("TEST_AI_SECURITY_PY"), "test_ai_security.py")
        r["api_tests"] = tests_guess


def step_patch_admin_security_imports(r: dict):
    head("STEP 2 -- Patch admin_security.py imports")

    routes_dir = r.get("api_routes")
    admin_file = routes_dir / "admin_security.py" if routes_dir else None

    if not admin_file or not admin_file.exists():
        warn("admin_security.py not placed -- skipping import patch")
        return

    auth_mod, auth_fn  = detect_auth_import(routes_dir)
    sess_mod, sess_fn  = detect_session_import(routes_dir)

    text = admin_file.read_text(encoding="utf-8")

    # Replace auth import line
    text = re.sub(
        r"from app\.core\.auth import get_current_user, require_roles",
        f"from {auth_mod} import get_current_user, {auth_fn}",
        text,
    )
    if auth_fn != "require_roles":
        text = text.replace("require_roles(", f"{auth_fn}(")

    # Replace session import
    text = re.sub(
        r"from app\.core\.database import get_async_session",
        f"from {sess_mod} import {sess_fn}",
        text,
    )
    if sess_fn != "get_async_session":
        text = text.replace("get_async_session", sess_fn)

    # Fix ai_governance import path if non-standard
    text = re.sub(
        r"from \.ai_governance import",
        "from app.services.ai_governance import",
        text,
    )

    admin_file.write_text(text, encoding="utf-8")
    ok(f"Patched imports: auth={auth_fn} session={sess_fn}")


def step_register_router(r: dict):
    head("STEP 3 -- Register admin_security router in FastAPI")

    main_py = r.get("api_main")
    if not main_py:
        warn("api/main.py not found -- skipping router registration")
        return

    backup(main_py)
    text = main_py.read_text(encoding="utf-8")

    if "admin_security" in text:
        ok("admin_security router already registered -- skipping")
        return

    import_block = "\nfrom app.routes.admin_security import router as security_router\n"
    include_block = "\napp.include_router(security_router)\n"

    # Insert import after last "from app.routes" import
    import_pat = r"(from app\.routes\.\w+ import[^\n]+\n)"
    matches = list(re.finditer(import_pat, text))
    if matches:
        last_import_end = matches[-1].end()
        text = text[:last_import_end] + import_block + text[last_import_end:]
    else:
        last_import = 0
        for m in re.finditer(r"^(import|from)\s", text, re.MULTILINE):
            last_import = m.end()
        if last_import:
            nl = text.find("\n", last_import)
            text = text[:nl+1] + import_block + text[nl+1:]
        else:
            text = import_block + text

    # Insert include_router before main entry point
    for anchor in [
        r"if __name__\s*==\s*['\"]__main__['\"]",
        r"uvicorn\.run\(",
        r"app\.run\(",
    ]:
        m = re.search(anchor, text)
        if m:
            text = text[:m.start()] + include_block + text[m.start():]
            break
    else:
        text += include_block

    main_py.write_text(text, encoding="utf-8")
    ok("Registered: app.include_router(security_router)")


def step_frontend_files(r: dict):
    head("STEP 4 -- Frontend files")

    pages   = r["pages_chartnav"]
    content = r["content_chartnav"]
    comps   = r["components_chartnav"]

    ensure_dir(pages)
    ensure_dir(content)
    ensure_dir(comps)

    write_file(pages   / "Security.tsx",             asset("SECURITY_TSX"),  "Security.tsx")
    write_file(content / "security.en.json",          asset("SECURITY_JSON"), "security.en.json")
    write_file(comps   / "HomepageSecurityStrip.tsx", asset("STRIP_TSX"),     "HomepageSecurityStrip.tsx")


def step_patch_app_tsx(r: dict):
    head("STEP 5 -- Patch App.tsx")

    app_tsx = r["app_tsx"]
    backup(app_tsx)
    text = app_tsx.read_text(encoding="utf-8")

    import_line = "import ChartnavSecurity from './pages/chartnav/Security';"
    if "ChartnavSecurity" not in text:
        pat = r"(import \w+ from ['\"]\.\/pages\/chartnav\/\w+['\"];?\n)"
        matches = list(re.finditer(pat, text))
        if matches:
            pos = matches[-1].end()
            text = text[:pos] + import_line + "\n" + text[pos:]
        else:
            last_imp = max((m.end() for m in re.finditer(r"^import ", text, re.MULTILINE)), default=0)
            nl = text.find("\n", last_imp)
            text = text[:nl+1] + import_line + "\n" + text[nl+1:]
        ok("Added: import ChartnavSecurity")
    else:
        ok("Import ChartnavSecurity already present")

    placeholder_pat = r"<Route\s+path=['\"]\/chartnav\/security['\"][^>]*/>\s*"
    real_route      = '<Route path="/chartnav/security" component={ChartnavSecurity} />\n'

    if re.search(placeholder_pat, text):
        text = re.sub(placeholder_pat, real_route, text)
        ok("Replaced: placeholder /chartnav/security -> ChartnavSecurity")
    elif 'path="/chartnav/security"' in text:
        if "ChartnavSecurity" not in text:
            text = re.sub(
                r'(path=["\']\/chartnav\/security["\'][^>]*component=\{)\w+(\})',
                r'\1ChartnavSecurity\2',
                text,
            )
        ok("Route /chartnav/security already present -- verified component")
    else:
        for anchor in [
            r"<Route\s+component=\{NotFound\}",
            r'<Route\s+path="\*"',
            r"</Switch>",
            r"</Routes>",
        ]:
            m = re.search(anchor, text)
            if m:
                text = text[:m.start()] + real_route + text[m.start():]
                ok("Added: <Route path='/chartnav/security' component={ChartnavSecurity} />")
                break
        else:
            warn("Could not find insertion point in App.tsx -- manual check needed")

    # Remove security from noindex/placeholder arrays
    text = re.sub(r"\s*['\"]\/chartnav\/security['\"],?\s*(?=])", "", text)
    text = re.sub(r",?\s*\{[^}]*path:\s*['\"]\/chartnav\/security['\"][^}]*\}", "", text)

    app_tsx.write_text(text, encoding="utf-8")
    ok("App.tsx patched")


def step_patch_sticky_nav(r: dict):
    head("STEP 6 -- Patch StickyNav")

    nav_file = r.get("sticky_nav")
    if not nav_file:
        for candidate in r["components_chartnav"].glob("**/*.tsx"):
            txt = candidate.read_text(errors="replace")
            if "security" in txt.lower() and ("href" in txt.lower() or "path" in txt.lower()):
                nav_file = candidate
                break

    if not nav_file:
        warn("StickyNav not found -- searching all component TSX files for nav links")
        for candidate in r["src_root"].rglob("*.tsx"):
            txt = candidate.read_text(errors="replace")
            if "/chartnav/security" in txt or ("Security" in txt and "nav" in txt.lower()):
                nav_file = candidate
                info(f"Found possible nav file: {candidate.name}")
                break

    if not nav_file:
        warn("StickyNav not found -- add Security link manually")
        return

    backup(nav_file)
    text = nav_file.read_text(encoding="utf-8")

    if "/chartnav/security" not in text:
        warn(f"No security link in {nav_file.name} -- may need manual addition")
        return

    text = re.sub(
        r"(\{[^}]*href:\s*['\"]\/chartnav\/security['\"][^}]*?)noindex:\s*true,?\s*",
        r"\1",
        text,
    )
    nav_file.write_text(text, encoding="utf-8")
    ok(f"StickyNav patched: {nav_file.name}")


def step_patch_home_json(r: dict):
    head("STEP 7 -- Patch home.en.json")

    home_json = r.get("home_json")
    if not home_json or not home_json.exists():
        warn("home.en.json not found -- skipping")
        return

    backup(home_json)
    data = json.loads(home_json.read_text(encoding="utf-8"))

    if "securityStrip" not in data:
        data["securityStrip"] = {
            "copy": "IBM watsonx-powered AI workflows, human review, role-based access, audit visibility, and security event logging -- built for organizations that cannot afford blind automation.",
            "linkLabel": "Security & Governance →",
            "linkHref": "/chartnav/security",
        }
        home_json.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
        ok("Added securityStrip key to home.en.json")
    else:
        ok("securityStrip already present in home.en.json")


def step_patch_home_tsx(r: dict):
    head("STEP 8 -- Patch Home.tsx")

    home_tsx = r.get("home_tsx")
    if not home_tsx or not home_tsx.exists():
        warn("Home.tsx not found -- skipping homepage strip")
        return

    backup(home_tsx)
    text = home_tsx.read_text(encoding="utf-8")

    strip_import = "import { HomepageSecurityStrip } from '../../components/chartnav/HomepageSecurityStrip';"

    if "HomepageSecurityStrip" not in text:
        pat = r"(import \{?[^}]+\}? from ['\"][./]*components\/chartnav\/[^'\"]+['\"];?\n)"
        matches = list(re.finditer(pat, text))
        if matches:
            pos = matches[-1].end()
            text = text[:pos] + strip_import + "\n" + text[pos:]
        else:
            last = max((m.end() for m in re.finditer(r"^import ", text, re.MULTILINE)), default=0)
            nl = text.find("\n", last)
            text = text[:nl+1] + strip_import + "\n" + text[nl+1:]
        ok("Added HomepageSecurityStrip import")
    else:
        ok("HomepageSecurityStrip import already present")

    strip_render = textwrap.dedent("""
      {content.securityStrip && (
        <HomepageSecurityStrip
          copy={content.securityStrip.copy}
          linkLabel={content.securityStrip.linkLabel}
          linkHref={content.securityStrip.linkHref}
        />
      )}
    """).strip()

    if "HomepageSecurityStrip" in text and "securityStrip" in text:
        ok("HomepageSecurityStrip render already present")
    else:
        anchors = [
            r"(</section>\s*\n)(?=\s*{?/\*[^*]*WORKFLOW|/\*\s*--\s*\d|{?\s*<[A-Z])",
            r"(<ProofChips[^/]*/>\s*\n)",
            r"(<Hero[^/]*/>\s*\n)",
        ]
        inserted = False
        for anchor in anchors:
            m = re.search(anchor, text)
            if m:
                pos = m.end()
                text = text[:pos] + "\n      " + strip_render + "\n" + text[pos:]
                ok("Inserted HomepageSecurityStrip render after hero/proof section")
                inserted = True
                break

        if not inserted:
            m = re.search(r"(\s*</div>\s*\);\s*\}?\s*$)", text)
            if m:
                text = text[:m.start()] + "\n      " + strip_render + text[m.start():]
                ok("Inserted HomepageSecurityStrip render (fallback position)")
            else:
                warn("Could not find insertion point for HomepageSecurityStrip -- add manually")

    home_tsx.write_text(text, encoding="utf-8")


def step_append_css(r: dict):
    head("STEP 9 -- Append security CSS to chartnav.css")

    css_file = r.get("chartnav_css")
    if not css_file or not css_file.exists():
        warn("chartnav.css not found -- skipping CSS")
        return

    backup(css_file)
    existing = css_file.read_text(encoding="utf-8")
    new_css  = asset("SECURITY_CSS")

    if "cn-sec-hero" in existing:
        ok("Security CSS already appended -- skipping")
        return

    with css_file.open("a", encoding="utf-8") as f:
        f.write("\n\n")
        f.write(new_css)

    ok(f"Appended {len(new_css):,} chars to chartnav.css")


def step_patch_sitemap(r: dict):
    head("STEP 10 -- Patch sitemap.xml")

    sitemap = r.get("sitemap")
    if not sitemap or not sitemap.exists():
        warn("sitemap.xml not found -- skipping")
        return

    backup(sitemap)
    text = sitemap.read_text(encoding="utf-8")

    if "/chartnav/security" in text:
        ok("sitemap.xml already includes /chartnav/security")
        return

    new_entry = textwrap.dedent("""
  <url>
    <loc>https://arcgsystems.com/chartnav/security</loc>
    <changefreq>monthly</changefreq>
    <priority>0.8</priority>
  </url>
""")

    if "</urlset>" in text:
        text = text.replace("</urlset>", new_entry + "</urlset>")
        sitemap.write_text(text, encoding="utf-8")
        ok("Added /chartnav/security to sitemap.xml")
    else:
        warn("sitemap.xml has no </urlset> tag -- check format")


def step_patch_robots(r: dict):
    head("STEP 11 -- Check robots.txt")

    robots = r.get("robots")
    if not robots or not robots.exists():
        warn("robots.txt not found -- skipping")
        return

    backup(robots)
    text = robots.read_text(encoding="utf-8")

    original = text
    text = re.sub(r"Disallow:\s*/chartnav/security\s*\n?", "", text)

    if text != original:
        robots.write_text(text, encoding="utf-8")
        ok("Removed Disallow: /chartnav/security from robots.txt")
    else:
        ok("robots.txt: /chartnav/security not disallowed -- nothing to do")


def step_chartnavmd_site(r: dict):
    head("STEP 12 -- chartnavmd-site")

    site_dir = r["root"] / "chartnavmd-site"
    ensure_dir(site_dir)
    write_file(site_dir / "index.html", asset("CHARTNAVMD_HTML"), "chartnavmd-site/index.html")
    write_file(site_dir / "vercel.json", _vercel_json(), "chartnavmd-site/vercel.json")
    dns_dir = r["root"] / "docs" / "deployment"
    ensure_dir(dns_dir)
    write_file(dns_dir / "chartnavmd-dns.md", asset("CHARTNAVMD_DNS_MD"), "docs/deployment/chartnavmd-dns.md")
    ok("chartnavmd-site ready for deployment")


def _vercel_json() -> str:
    return json.dumps({
        "version": 2,
        "cleanUrls": True,
        "trailingSlash": False,
        "headers": [{
            "source": "/(.*)",
            "headers": [
                {"key": "X-Content-Type-Options",   "value": "nosniff"},
                {"key": "X-Frame-Options",           "value": "DENY"},
                {"key": "Referrer-Policy",           "value": "strict-origin-when-cross-origin"},
                {"key": "Strict-Transport-Security", "value": "max-age=63072000; includeSubDomains; preload"},
                {"key": "Permissions-Policy",        "value": "camera=(), microphone=(), geolocation=()"},
            ],
        }],
        "redirects": [
            {"source": "/assessment", "destination": "/#assessment", "permanent": False},
            {"source": "/security",   "destination": "/#security",   "permanent": False},
        ],
    }, indent=2)

# ── Validation ─────────────────────────────────────────────────────────────────

def step_run_pytest(r: dict) -> bool:
    head("STEP 13 -- pytest")

    api_root = r.get("api_root")
    tests    = r.get("api_tests")
    if not api_root or not tests:
        warn("No API root or tests dir -- skipping pytest")
        return False

    test_file = tests / "test_ai_security.py"
    if not test_file.exists():
        warn(f"test_ai_security.py not found at {test_file}")
        return False

    cmd = ["python3", "-m", "pytest", str(test_file), "-v", "--tb=short"]
    info(f"Running: {' '.join(cmd)}")
    result = subprocess.run(cmd, cwd=str(api_root), capture_output=False)

    if result.returncode == 0:
        ok("pytest: all tests passed")
        return True
    else:
        warn("pytest: some tests failed -- check import paths")
        return False


def step_run_build(r: dict) -> bool:
    head("STEP 14 -- npm run build")

    npm_cwd = r.get("npm_cwd")
    if not npm_cwd:
        warn("package.json not found -- skipping npm build")
        return False

    info(f"Running: npm run build  (cwd: {npm_cwd})")
    result = subprocess.run(["npm", "run", "build"], cwd=str(npm_cwd), capture_output=False)

    if result.returncode == 0:
        ok("npm run build: succeeded")
        return True
    else:
        err("npm run build: FAILED -- check TypeScript errors above")
        return False

# ── Final status report ────────────────────────────────────────────────────────

def _css_patched(r):
    css = r.get("chartnav_css")
    return bool(css and css.exists() and "cn-sec-hero" in css.read_text(errors="replace"))

def _route_registered(r):
    app = r.get("app_tsx")
    return bool(app and app.exists() and "ChartnavSecurity" in app.read_text(errors="replace"))

def _sitemap_has_security(r):
    s = r.get("sitemap")
    return bool(s and s.exists() and "/chartnav/security" in s.read_text(errors="replace"))

def _home_json_has_strip(r):
    h = r.get("home_json")
    return bool(h and h.exists() and "securityStrip" in h.read_text(errors="replace"))


def print_report(r: dict, pytest_ok: bool, build_ok: bool):
    head("=" * 52)
    head("FINAL STATUS REPORT")
    head("=" * 52)

    checks = [
        ("Backend: ai_governance.py",          (r.get("api_services") / "ai_governance.py").exists()  if r.get("api_services") else False),
        ("Backend: ai_security.py",            (r.get("api_services") / "ai_security.py").exists()    if r.get("api_services") else False),
        ("Backend: admin_security.py",         (r.get("api_routes")   / "admin_security.py").exists() if r.get("api_routes")   else False),
        ("Frontend: Security.tsx",             (r["pages_chartnav"]      / "Security.tsx").exists()),
        ("Frontend: security.en.json",         (r["content_chartnav"]    / "security.en.json").exists()),
        ("Frontend: HomepageSecurityStrip.tsx",(r["components_chartnav"] / "HomepageSecurityStrip.tsx").exists()),
        ("Frontend: chartnav.css patched",      _css_patched(r)),
        ("App.tsx: /chartnav/security route",   _route_registered(r)),
        ("sitemap.xml: /chartnav/security",     _sitemap_has_security(r)),
        ("home.en.json: securityStrip",         _home_json_has_strip(r)),
        ("chartnavmd-site/index.html",          (r["root"] / "chartnavmd-site" / "index.html").exists()),
        ("pytest",      pytest_ok),
        ("npm build",   build_ok),
    ]

    blockers = []
    for label, status in checks:
        if status:
            ok(label)
        else:
            err(label)
            blockers.append(label)

    print()
    if blockers:
        print(f"{RED}{BOLD}REMAINING BLOCKERS:{RESET}")
        for b in blockers:
            print(f"  {RED}* {b}{RESET}")
    else:
        print(f"{GREEN}{BOLD}All checks passed. Security integration complete.{RESET}")

    print(f"""
{BOLD}Manual steps still required:{RESET}

1. Set  VITE_CHARTNAV_LEAD_WEBHOOK  env var (forms are console-log-only until set)
2. Ship og.jpg  ->  public/chartnav/og.jpg
3. Ship og.jpg  ->  chartnavmd-site/og.jpg
4. Configure GoDaddy DNS for chartnavmd.com (see docs/deployment/chartnavmd-dns.md)
5. Legal review of "What We Do Not Claim" section before publishing
6. Confirm chartnav@arcgsystems.com is monitored for assessment form submissions
""")

# ── Entry point ────────────────────────────────────────────────────────────────

def main():
    global BACKUP_DIR

    repo_root = Path(sys.argv[1]).resolve() if len(sys.argv) > 1 else Path.cwd()
    ts        = datetime.now().strftime("%Y%m%d_%H%M%S")
    BACKUP_DIR = repo_root / ".chartnav_security_backup" / ts

    print(f"\n{BOLD}ChartNav Security Integration Executor{RESET}")
    print(f"Repo root : {repo_root}")
    print(f"Backup dir: {BACKUP_DIR}")
    print(f"Started   : {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")

    try:
        _ = asset("AI_GOVERNANCE_PY")
    except RuntimeError:
        err("Assets not embedded. Something went wrong with the script.")
        sys.exit(1)

    r = detect_repo(repo_root)
    r["root"] = repo_root

    step_backend(r)
    step_patch_admin_security_imports(r)
    step_register_router(r)
    step_frontend_files(r)
    step_patch_app_tsx(r)
    step_patch_sticky_nav(r)
    step_patch_home_json(r)
    step_patch_home_tsx(r)
    step_append_css(r)
    step_patch_sitemap(r)
    step_patch_robots(r)
    step_chartnavmd_site(r)
    pytest_ok = step_run_pytest(r)
    build_ok  = step_run_build(r)

    print_report(r, pytest_ok, build_ok)


if __name__ == "__main__":
    main()
